/**
 * @summary Register a stock movement
 */
export const getCreateMovementUrl = () => {
  return `/api/movements`;
};

export const createMovement = async (
  createMovementInput: CreateMovementInput,
  options?: RequestInit,
): Promise<Movement> => {
  return customFetch<Movement>(getCreateMovementUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(createMovementInput),
  });
};

export const getCreateMovementMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof createMovement>>,
    TError,
    { data: BodyType<CreateMovementInput> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof createMovement>>,
  TError,
  { data: BodyType<CreateMovementInput> },
  TContext
> => {
  const mutationKey = ["createMovement"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof createMovement>>,
    { data: BodyType<CreateMovementInput> }
  > = (props) => {
    const { data } = props ?? {};

    return createMovement(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type CreateMovementMutationResult = NonNullable<
  Awaited<ReturnType<typeof createMovement>>
>;
export type CreateMovementMutationBody = BodyType<CreateMovementInput>;
export type CreateMovementMutationError = ErrorType<unknown>;

/**
 * @summary Register a stock movement
 */
export const useCreateMovement = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof createMovement>>,
    TError,
    { data: BodyType<CreateMovementInput> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof createMovement>>,
  TError,
  { data: BodyType<CreateMovementInput> },
  TContext
> => {
  return useMutation(getCreateMovementMutationOptions(options));
};

